// elemwise: need tmp1 (tileLenOut), tmp2 (tileLenOut), tanhBuf (tileLenOut)
// groupnorm: need sumBuf (groupSize), varBuf (groupSize)
// We'll keep conservative: 192KB = 49152 floats.
static constexpr uint32_t UB_BUDGET_FLOATS = 49152;
static constexpr uint32_t ALIGN_ELEMS = 128;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

