    // Want: tileLenIn * tileLenOut floats for weight tile; plus inBuf, outBuf, temps.
    // We need tileLenOut + tileLenIn + tileLenIn*tileLenOut + 3*tileLenOut + 2*groupSize <= UB_BUDGET_FLOATS
